"""
URL bijgewerkt: hestys-stock-screener.streamlit.app -> hestys.streamlit.app
(in alle mail-templates, 5 plekken in 3 bestanden). Ook een kapotte link
gefixt die stiekem al bestond: '?view=analyse' (oude spelling van vóór de
Analyze-hernoeming) -> '?view=analyze'.

BELANGRIJKE HANDMATIGE VERVOLGSTAPPEN (kan niet vanuit hier gedaan worden):

1. Streamlit Cloud -> je app -> kebab-menu -> Settings -> General ->
   verander de subdomain naar 'hestys' (wordt dan hestys.streamlit.app)
   Let op: je OUDE url geeft daarna een 404 -- bij weinig verkeer nu
   het beste moment om deze knip te maken.

2. Werk 'secrets.toml' bij (lokaal EN Streamlit Cloud), de [app] url:
   [app]
   url = "https://hestys.streamlit.app"
   (geen trailing slash)

3. Werk ook je Google OAuth 'Authorized redirect URIs' bij in de Google
   Cloud Console -- die verwijzen nu nog naar de oude URL, en zonder
   deze update werkt inloggen niet meer na de naamswijziging.

Gebruik: python fix_url_rename.py
Draai dit vanuit je stock_screener-map.
"""

PORTFOLIO_WATCH_CONTENT = '"""\nPortfolio Watch: volgt de HUIDIGE Supertrend-status van je eigen bestaande\nposities (in tegenstelling tot screener.py, dat naar NIEUWE ideeën in\nAEX/Nasdaq-100 zoekt). Dit is vooral relevant bij een geconcentreerde\nportfolio -- weten of je grootste positie (bv. Tesla) nog steeds in een\nbullish trend zit, is vaak belangrijker dan een willekeurig nieuw signaal.\n\nBELANGRIJK: check en corrigeer de tickers hieronder. Vooral crypto,\nkleine fondsen en niet-beursgenoteerde/private-equity-achtige posities\n(zoals SpaceX-exposure-producten) hebben vaak een niet voor de hand\nliggende Yahoo Finance-ticker, of zijn er soms helemaal niet in te vinden.\n\nVereist: pip install -r requirements.txt\n\nGebruik: python portfolio_watch.py\n"""\nfrom __future__ import annotations\n\nimport pandas as pd\nimport yfinance as yf\n\nfrom indicators import supertrend, ema, resample_to_weekly\nfrom screener import get_roic_data, fetch_weekly, get_recent_news\nfrom emailer import send_email, is_configured as email_is_configured\n\n# --- Jouw posities. CONTROLEER elke ticker, vooral de onderstaande met een \'?\' ---\nPORTFOLIO_HOLDINGS = [\n    {"naam": "Tesla", "ticker": "TSLA"},\n    {"naam": "Bitcoin", "ticker": "BTC-EUR"},\n    {"naam": "Solana", "ticker": "SOL-EUR"},\n    {"naam": "Telcoin", "ticker": "TEL-USD"},\n    {"naam": "AST SpaceMobile", "ticker": "ASTS"},\n    {"naam": "Hims & Hers", "ticker": "HIMS"},\n    {"naam": "Duolingo", "ticker": "DUOL"},\n    {"naam": "Semiconductors ETF", "ticker": "SMH"},\n    {"naam": "TDIV Dividend Leaders ETF", "ticker": "TDIV"},  # ? controleer exacte notering/beurs\n    {"naam": "SpaceX", "ticker": "SPCX"},  # IPO 12 juni 2026 -- nog te weinig historie voor weekly Supertrend\n    # PROP.COM (fractioneel vastgoed Dubai) is een niet-beursgenoteerd\n    # exposure-product zonder ticker -- hier bewust weggelaten.\n]\n\nATR_LENGTH = 6\nATR_MULTIPLIER = 2.6\nTREND_FILTER_EMA_LENGTH = 20\nRECENT_CHANGE_WEEKS = 2  # een statusverandering binnen dit aantal weken wordt als \'LET OP\' gemarkeerd\nNEWS_DAYS_BACK = 7       # hoe recent nieuws moet zijn om meegenomen te worden\nNEWS_MAX_ITEMS = 3       # max. aantal nieuwsberichten per positie\n\n\ndef check_holding(naam: str, ticker: str):\n    # Nieuws is onafhankelijk van of er genoeg historie is voor Supertrend --\n    # altijd proberen op te halen, ook als de technische check hieronder faalt.\n    news_items = get_recent_news(ticker, max_items=NEWS_MAX_ITEMS, days_back=NEWS_DAYS_BACK)\n\n    try:\n        df = fetch_weekly(ticker)\n    except Exception as exc:\n        print(f"  {naam} ({ticker}): fout bij ophalen ({exc})")\n        return {\n            "naam": naam, "ticker": ticker, "status": "ONBEKEND (fout bij ophalen)",\n            "sinds": None, "weken_in_trend": None, "recent_gewijzigd": False,\n            "prijs": None, "boven_ema20": None, "roic_pct": None, "roic_trend": "onbekend",\n            "nieuws": news_items,\n        }\n\n    min_needed = max(ATR_LENGTH, TREND_FILTER_EMA_LENGTH) + 5\n    if df.empty or len(df) < min_needed:\n        print(f"  {naam} ({ticker}): te weinig data voor Supertrend (nodig: {min_needed}, "\n              f"gekregen: {len(df)}) -- nieuws wordt wel getoond")\n        latest_price = round(float(df[\'close\'].iloc[-1]), 2) if not df.empty else None\n        return {\n            "naam": naam, "ticker": ticker, "status": "ONBEKEND (te weinig historie)",\n            "sinds": None, "weken_in_trend": None, "recent_gewijzigd": False,\n            "prijs": latest_price, "boven_ema20": None, "roic_pct": None, "roic_trend": "onbekend",\n            "nieuws": news_items,\n        }\n\n    st = supertrend(df, length=ATR_LENGTH, multiplier=ATR_MULTIPLIER)\n    df = df.copy()\n    df["trend_dir"] = st["trend_dir"]\n    df["ema_trend"] = ema(df["close"], TREND_FILTER_EMA_LENGTH)\n\n    current_trend = int(df["trend_dir"].iloc[-1])\n    trend_changes = df.index[df["trend_dir"] != df["trend_dir"].shift(1)]\n    last_change = trend_changes[-1] if len(trend_changes) > 0 else df.index[0]\n    weeks_in_current_trend = len(df.loc[last_change:]) - 1\n\n    latest_row = df.iloc[-1]\n    roic_data = get_roic_data(ticker)\n\n    return {\n        "naam": naam,\n        "ticker": ticker,\n        "status": "BULLISH" if current_trend == 1 else "BEARISH",\n        "sinds": last_change.date(),\n        "weken_in_trend": weeks_in_current_trend,\n        "recent_gewijzigd": weeks_in_current_trend <= RECENT_CHANGE_WEEKS,\n        "prijs": round(float(latest_row["close"]), 2),\n        "boven_ema20": bool(latest_row["close"] > latest_row["ema_trend"]),\n        "roic_pct": round(roic_data["roic"] * 100, 1) if roic_data["roic"] is not None else None,\n        "roic_trend": roic_data["roic_trend"],\n        "nieuws": news_items,\n    }\n\n\ndef build_email_body(df: pd.DataFrame) -> tuple:\n    """Bouwt de Portfolio Watch-mail -- zelfde Hesty\'s-stijl als de dagelijkse/wekelijkse signalen-mails."""\n    changed = df[df["recent_gewijzigd"]]\n\n    # --- Tekst-versie ---\n    text_lines = ["Good morning from Hesty\'s -- here\'s your portfolio watch.", ""]\n\n    if len(changed) > 0:\n        text_lines.append(f"🔄 {len(changed)} position(s) just flipped trend:")\n        for _, row in changed.iterrows():\n            text_lines.append(f"  - {row[\'naam\']} ({row[\'ticker\']}): now {row[\'status\']} since {row[\'sinds\']}")\n        text_lines.append("")\n\n    text_lines.append(f"Full overview ({len(df)} positions):")\n    for _, row in df.iterrows():\n        roic_txt = f"{row[\'roic_pct\']:+.1f}% ({row[\'roic_trend\']})" if row["roic_pct"] is not None else "unknown"\n        text_lines.append(\n            f"  - {row[\'naam\']} ({row[\'ticker\']}): {row[\'status\']} since {row[\'sinds\']} "\n            f"({row[\'weken_in_trend\']} weeks), price {row[\'prijs\']}, ROIC: {roic_txt}"\n        )\n\n    text_lines.append("")\n    text_lines.append("Recent news (last 7 days):")\n    any_news = False\n    for _, row in df.iterrows():\n        if row["nieuws"]:\n            any_news = True\n            text_lines.append(f"\\n{row[\'naam\']} ({row[\'ticker\']}):")\n            for item in row["nieuws"]:\n                text_lines.append(f"  - [{item[\'published\'].strftime(\'%Y-%m-%d\')}] {item[\'title\']} ({item[\'publisher\']})")\n                if item["link"]:\n                    text_lines.append(f"    {item[\'link\']}")\n    if not any_news:\n        text_lines.append("No recent news found for your positions.")\n\n    text_lines += [\n        "",\n        "See the full analysis under Analyze on the site.",\n        "",\n        "-- Hesty\'s, your personal investment assistant",\n        "",\n        "This is a screener, not investment advice.",\n    ]\n    text_body = "\\n".join(text_lines)\n\n    # --- HTML-versie: lichte achtergrond met jade accent, zelfde stijl als\n    # de dagelijkse/wekelijkse mail ---\n    def _row_html(r):\n        roic_str = f"{r[\'roic_pct\']:+.1f}%" if r["roic_pct"] is not None else "-"\n        status_color = "#0F8F6E" if r["status"] == "BULLISH" else "#C1524A"\n        row_bg = "background-color:#EAF7F3;" if r["recent_gewijzigd"] else ""\n        return (\n            f"<tr style=\'border-bottom:1px solid #E5E8EC;{row_bg}\'>"\n            f"<td style=\'padding:8px;font-weight:600;color:#101825;\'>{r[\'naam\']}</td>"\n            f"<td style=\'padding:8px;color:#5B6472;\'>{r[\'ticker\']}</td>"\n            f"<td style=\'padding:8px;font-weight:600;color:{status_color};\'>{r[\'status\']}</td>"\n            f"<td style=\'padding:8px;color:#5B6472;\'>{r[\'sinds\']}</td>"\n            f"<td style=\'padding:8px;color:#5B6472;\'>{r[\'weken_in_trend\']}</td>"\n            f"<td style=\'padding:8px;color:#101825;\'>{r[\'prijs\']}</td>"\n            f"<td style=\'padding:8px;color:#5B6472;\'>{roic_str}</td>"\n            f"</tr>"\n        )\n\n    rows_html = "".join(_row_html(r) for _, r in df.iterrows())\n\n    def _news_html(row):\n        if not row["nieuws"]:\n            return ""\n        items_html = "".join(\n            f"<li style=\'padding:4px 0;\'><a href=\\"{item[\'link\']}\\" style=\'color:#1FAE96;text-decoration:none;font-weight:600;\'>{item[\'title\']}</a> "\n            f"<span style=\'color:#9AA1AC;font-size:12px;\'>({item[\'publisher\']}, {item[\'published\'].strftime(\'%Y-%m-%d\')})</span></li>"\n            for item in row["nieuws"]\n        )\n        return (f"<p style=\'margin:16px 0 4px 0;font-weight:700;color:#101825;\'>{row[\'naam\']} ({row[\'ticker\']})</p>"\n                f"<ul style=\'margin:0;padding-left:20px;\'>{items_html}</ul>")\n\n    news_html = "".join(_news_html(r) for _, r in df.iterrows())\n    if not news_html:\n        news_html = "<p style=\'color:#5B6472;\'>No recent news found for your positions.</p>"\n\n    flip_banner = ""\n    if len(changed) > 0:\n        flip_banner = (\n            f"<p style=\'background:#FFF3CD;padding:10px 14px;border-radius:8px;font-size:14px;color:#101825;margin-top:0;\'>"\n            f"🔄 {len(changed)} position(s) just flipped trend -- see highlighted rows below.</p>"\n        )\n\n    html_body = f"""\n    <div style="font-family: -apple-system, \'Segoe UI\', Roboto, Arial, sans-serif; max-width: 600px; margin: 0 auto; background:#ffffff;">\n        <div style="background:#101825; padding: 28px 24px; border-radius: 12px 12px 0 0;">\n            <div style="color:#1FAE96; font-size:13px; font-weight:600; letter-spacing:1px; text-transform:uppercase;">Hesty\'s Portfolio Watch</div>\n            <div style="color:#EAEDF1; font-size:22px; font-weight:700; margin-top:4px;">Your positions, checked</div>\n        </div>\n        <div style="padding: 24px; border: 1px solid #E5E8EC; border-top: none; border-radius: 0 0 12px 12px;">\n            {flip_banner}\n            <table style="width:100%; border-collapse:collapse; margin-top:16px; font-size:14px;">\n                <tr style="border-bottom:2px solid #101825;">\n                    <th style="text-align:left; padding:8px; font-size:11px; color:#5B6472; text-transform:uppercase;">Name</th>\n                    <th style="text-align:left; padding:8px; font-size:11px; color:#5B6472; text-transform:uppercase;">Ticker</th>\n                    <th style="text-align:left; padding:8px; font-size:11px; color:#5B6472; text-transform:uppercase;">Trend</th>\n                    <th style="text-align:left; padding:8px; font-size:11px; color:#5B6472; text-transform:uppercase;">Since</th>\n                    <th style="text-align:left; padding:8px; font-size:11px; color:#5B6472; text-transform:uppercase;">Weeks</th>\n                    <th style="text-align:left; padding:8px; font-size:11px; color:#5B6472; text-transform:uppercase;">Price</th>\n                    <th style="text-align:left; padding:8px; font-size:11px; color:#5B6472; text-transform:uppercase;">ROIC</th>\n                </tr>\n                {rows_html}\n            </table>\n\n            <h4 style="color:#101825; font-size:16px; margin:24px 0 8px 0;">📰 Recent news</h4>\n            {news_html}\n\n            <p style="margin-top:20px; font-size:14px; color:#5B6472; line-height:1.5;">\n                See the full analysis under\n                <a href="https://hestys.streamlit.app/?view=analyze" style="color:#1FAE96; font-weight:600; text-decoration:none;">Analyze</a> on the site.\n            </p>\n            <p style="margin-top:24px; font-size:14px; color:#101825; font-weight:600;">&mdash; Hesty\'s, your personal investment assistant</p>\n            <p style="margin-top:16px; font-size:12px; color:#9AA1AC; font-style:italic;">This is a screener, not investment advice.</p>\n        </div>\n    </div>\n    """\n    return text_body, html_body\n\n\ndef main() -> None:\n    print(f"Portfolio Watch: {len(PORTFOLIO_HOLDINGS)} posities checken "\n          f"(weekly, ATR-periode {ATR_LENGTH}, multiplier {ATR_MULTIPLIER})...\\n")\n\n    results = []\n    for holding in PORTFOLIO_HOLDINGS:\n        result = check_holding(holding["naam"], holding["ticker"])\n        if result:\n            results.append(result)\n            marker = " <-- LET OP, recent gewijzigd" if result["recent_gewijzigd"] else ""\n            if result["sinds"] is not None:\n                print(f"  {result[\'naam\']}: {result[\'status\']} sinds {result[\'sinds\']} "\n                      f"({result[\'weken_in_trend\']} weken){marker}")\n            else:\n                print(f"  {result[\'naam\']}: {result[\'status\']}")\n\n    if not results:\n        print("\\nGeen enkele positie kon gecheckt worden -- controleer je tickers.")\n        return\n\n    df = pd.DataFrame(results)\n    # \'nieuws\' is een lijst-per-rij -- hoort niet netjes in een CSV-cel of\n    # brede tabel, laten we dat weg en tonen het apart\n    df.drop(columns=["nieuws"]).to_csv("portfolio_watch.csv", index=False)\n\n    # Nieuws apart opslaan als JSON, zodat het dashboard dit kan tonen\n    # zonder alles opnieuw op te hoeven halen\n    import json\n    news_export = {}\n    for _, row in df.iterrows():\n        news_export[row["ticker"]] = [\n            {**item, "published": item["published"].isoformat()} for item in row["nieuws"]\n        ]\n    with open("portfolio_watch_news.json", "w", encoding="utf-8") as f:\n        json.dump(news_export, f, ensure_ascii=False, indent=2)\n\n    print(f"\\n=== OVERZICHT ===\\n")\n    print(df.drop(columns=["nieuws"]).to_string(index=False))\n\n    print("\\n=== RECENT NIEUWS (laatste 7 dagen) ===")\n    any_news = False\n    for _, row in df.iterrows():\n        if row["nieuws"]:\n            any_news = True\n            print(f"\\n{row[\'naam\']} ({row[\'ticker\']}):")\n            for item in row["nieuws"]:\n                print(f"  - [{item[\'published\'].strftime(\'%Y-%m-%d\')}] {item[\'title\']} ({item[\'publisher\']})")\n                if item["link"]:\n                    print(f"    {item[\'link\']}")\n    if not any_news:\n        print("  Geen recent nieuws gevonden voor je posities.")\n\n    print("\\nOpgeslagen in \'portfolio_watch.csv\'.")\n\n    if email_is_configured():\n        text_body, html_body = build_email_body(df)\n        n_changed = df["recent_gewijzigd"].sum()\n        subject = f"Portfolio Watch: {n_changed} wijziging(en)" if n_changed > 0 else "Portfolio Watch: geen wijzigingen"\n        send_email(subject=subject, body_text=text_body, body_html=html_body)\n    else:\n        print("\\n(E-mail niet verstuurd: nog niet ingesteld in .env.)")\n\n\nif __name__ == "__main__":\n    main()\n'

SCREENER_DAILY_CONTENT = '"""\nDagelijkse variant van screener.py -- zelfde signaal-logica (Supertrend-\nomslag + ROIC + winst-verrassing + fair value + relatieve sterkte), maar\nop DAGELIJKSE candles i.p.v. wekelijkse, met instellingen die daarbij\npassen (kortere periodes). Bedoeld voor swing trades (dagen-weken), naast\nde bestaande wekelijkse screener (voor lange-termijn-overtuigingen).\n\nBewust een APART bestand i.p.v. de bestaande, uitgebreid-afgestelde\nscreener.py aan te passen -- dat voorkomt dat wijzigingen hier de\ngoed-werkende wekelijkse screener zouden kunnen breken. Hergebruikt wel\nalle tijdschaal-onafhankelijke bouwstenen (tickerlijsten, ROIC,\nwinst-verrassing, fair value, nieuws) via import.\n\nGebruik: python screener_daily.py\n"""\nfrom __future__ import annotations\n\nimport pandas as pd\nimport yfinance as yf\n\nfrom indicators import supertrend, ema, volume_ratio\nfrom screener import (\n    FALLBACK_TICKERS, BENCHMARKS, DEFAULT_BENCHMARK,\n    fetch_aex_tickers, fetch_nasdaq100_tickers, fetch_sp500_tickers,\n    fetch_dax_tickers, fetch_cac40_tickers, build_ticker_list,\n    get_benchmark_for_ticker, get_trailing_return_pct, get_prior_trend_duration,\n    get_roic_data, get_earnings_surprise, get_fair_value_estimate,\n)\nfrom emailer import send_email, is_configured as email_is_configured\n\n# --- Instellingen, geschaald voor dagelijkse candles (i.p.v. wekelijkse) ---\nATR_LENGTH = 10\nATR_MULTIPLIER = 3.0\nLOOKBACK_DAYS_FOR_SIGNAL = 2       # hoe \'vers\' een omslag moet zijn (i.p.v. 2 WEKEN bij de wekelijkse variant)\nTREND_FILTER_EMA_LENGTH = 50       # bredere-trend-context (i.p.v. 20 WEKEN)\nYEARS_OF_HISTORY = 2\nBENCHMARK_LOOKBACK_DAYS = 60       # relatieve-sterkte-vergelijkingsperiode (i.p.v. 12 WEKEN)\nVOLUME_AVG_DAYS = 20\nMIN_PRIOR_TREND_DAYS = 15          # zigzag-ruis-filter (i.p.v. 8 WEKEN)\nEARNINGS_RELEVANCE_DAYS = 45       # hoe recent winstcijfers moeten zijn (i.p.v. 8 WEKEN)\n\n\ndef fetch_daily(ticker: str, years: int = YEARS_OF_HISTORY) -> pd.DataFrame:\n    """Haalt dagelijkse OHLCV-data op -- GEEN resampling naar weekly, in tegenstelling tot screener.py."""\n    df = yf.download(ticker, period=f"{years}y", interval="1d", auto_adjust=True, progress=False)\n    if df.empty:\n        return df\n    if isinstance(df.columns, pd.MultiIndex):\n        df.columns = [c[0].lower() for c in df.columns]\n    else:\n        df.columns = [c.lower() for c in df.columns]\n    df = df[["open", "high", "low", "close", "volume"]]\n    return df\n\n\ndef fetch_benchmark_returns_daily() -> dict:\n    """Haalt voor elke benchmark-index 1x het trailing-rendement op (dagelijkse basis)."""\n    returns = {}\n    for benchmark_ticker in set(list(BENCHMARKS.values()) + [DEFAULT_BENCHMARK]):\n        try:\n            df_bench = fetch_daily(benchmark_ticker)\n            returns[benchmark_ticker] = get_trailing_return_pct(df_bench, BENCHMARK_LOOKBACK_DAYS)\n        except Exception as exc:\n            print(f"Kon benchmark {benchmark_ticker} niet ophalen: {exc}")\n            returns[benchmark_ticker] = None\n    return returns\n\n\ndef compute_score_daily(result: dict) -> float:\n    """\n    Zelfde score-opbouw als screener.py\'s compute_score (0-10, dezelfde\n    gewichten), maar met dag-gebaseerde versheid/relevantie-drempels i.p.v.\n    week-gebaseerde.\n    """\n    freshness_score = max(0.0, (LOOKBACK_DAYS_FOR_SIGNAL - result["dagen_geleden"]) / LOOKBACK_DAYS_FOR_SIGNAL * 1.5)\n\n    if result["roic_pct"] is not None:\n        level_points = min(max(result["roic_pct"], 0), 30) / 30 * 1.0\n        trend_points = 0.5 if result["roic_trend"] == "stijgend" else (-0.5 if result["roic_trend"] == "dalend" else 0)\n        roic_score = max(0.0, min(1.5, level_points + trend_points + 0.5))\n    else:\n        roic_score = 0.75\n\n    if result["relatieve_sterkte"] is not None:\n        clamped = min(max(result["relatieve_sterkte"], -20), 20)\n        rs_score = (clamped + 20) / 40 * 2.5\n    else:\n        rs_score = 1.25\n\n    if result.get("volume_bevestigd") is not None:\n        volume_score = 1.0 if result["volume_bevestigd"] else 0.0\n    else:\n        volume_score = 0.5\n\n    is_recent_enough = (\n        result.get("dagen_sinds_earnings") is not None\n        and result["dagen_sinds_earnings"] <= EARNINGS_RELEVANCE_DAYS\n    )\n    if result.get("earnings_surprise_pct") is not None and is_recent_enough:\n        clamped_surprise = min(max(result["earnings_surprise_pct"], -10), 10)\n        earnings_score = (clamped_surprise + 10) / 20 * 1.5\n    else:\n        earnings_score = 0.75\n\n    if result.get("afwijking_fair_value_pct") is not None:\n        clamped_fv = min(max(result["afwijking_fair_value_pct"], -30), 30)\n        fair_value_score = (30 - clamped_fv) / 60 * 2.0\n    else:\n        fair_value_score = 1.0\n\n    return round(\n        freshness_score + roic_score + rs_score + volume_score + earnings_score + fair_value_score, 2\n    )\n\n\ndef check_ticker_daily(ticker: str, benchmark_returns: dict, df: pd.DataFrame = None):\n    if df is None:\n        try:\n            df = fetch_daily(ticker)\n        except Exception as exc:\n            print(f"  {ticker}: fout bij ophalen ({exc})")\n            return None\n\n    min_needed = max(ATR_LENGTH, TREND_FILTER_EMA_LENGTH) + 5\n    if df.empty or len(df) < min_needed:\n        print(f"  {ticker}: te weinig data (nodig: {min_needed}, gekregen: {len(df)})")\n        return None\n\n    st = supertrend(df, length=ATR_LENGTH, multiplier=ATR_MULTIPLIER)\n    df = df.copy()\n    df["trend_dir"] = st["trend_dir"]\n    df["ema_trend"] = ema(df["close"], TREND_FILTER_EMA_LENGTH)\n    df["volume_ratio"] = volume_ratio(df["volume"], length=VOLUME_AVG_DAYS)\n\n    flips = df.index[(df["trend_dir"] == 1) & (df["trend_dir"].shift(1) == -1)]\n    if len(flips) == 0:\n        return None\n\n    last_flip = flips[-1]\n    days_since_flip = len(df.loc[last_flip:]) - 1\n    if days_since_flip > LOOKBACK_DAYS_FOR_SIGNAL:\n        return None\n\n    prior_trend_days = get_prior_trend_duration(df, last_flip)\n    if prior_trend_days < MIN_PRIOR_TREND_DAYS:\n        return None  # waarschijnlijk zigzag-ruis binnen een al lopende trend\n\n    flip_row = df.loc[last_flip]\n    latest_row = df.iloc[-1]\n\n    benchmark_ticker = get_benchmark_for_ticker(ticker)\n    own_return = get_trailing_return_pct(df, BENCHMARK_LOOKBACK_DAYS)\n    benchmark_return = benchmark_returns.get(benchmark_ticker)\n    relative_strength = (\n        round(own_return - benchmark_return, 2)\n        if own_return is not None and benchmark_return is not None\n        else None\n    )\n\n    volume_confirmed = (\n        bool(flip_row["volume_ratio"] > 1) if pd.notna(flip_row["volume_ratio"]) else None\n    )\n\n    result = {\n        "ticker": ticker,\n        "flip_date": last_flip.date(),\n        "dagen_geleden": days_since_flip,\n        "voorgaande_trend_dagen": prior_trend_days,\n        "prijs_bij_omslag": round(float(flip_row["close"]), 2),\n        "prijs_nu": round(float(latest_row["close"]), 2),\n        "sinds_omslag_pct": round((latest_row["close"] / flip_row["close"] - 1) * 100, 2),\n        "boven_ema": bool(latest_row["close"] > latest_row["ema_trend"]),\n        "benchmark": benchmark_ticker,\n        "relatieve_sterkte": relative_strength,\n        "volume_bevestigd": volume_confirmed,\n    }\n\n    roic_data = get_roic_data(ticker)\n    result["roic_pct"] = round(roic_data["roic"] * 100, 1) if roic_data["roic"] is not None else None\n    result["roic_trend"] = roic_data["roic_trend"]\n\n    earnings_data = get_earnings_surprise(ticker)\n    result["earnings_surprise_pct"] = (\n        round(earnings_data["surprise_pct"], 1) if earnings_data["surprise_pct"] is not None else None\n    )\n    result["earnings_beat"] = earnings_data["beat"]\n    result["earnings_date"] = (\n        earnings_data["earnings_date"].date() if earnings_data["earnings_date"] is not None else None\n    )\n    if earnings_data["earnings_date"] is not None:\n        days_since_earnings = (pd.Timestamp.now(tz=earnings_data["earnings_date"].tz) - earnings_data["earnings_date"]).days\n        result["dagen_sinds_earnings"] = max(0, days_since_earnings)\n    else:\n        result["dagen_sinds_earnings"] = None\n\n    fair_value_data = get_fair_value_estimate(ticker)\n    result["fair_value"] = fair_value_data["fair_value"]\n    result["afwijking_fair_value_pct"] = fair_value_data["afwijking_pct"]\n\n    result["score"] = compute_score_daily(result)\n\n    return result\n\n\ndef build_no_signals_email_daily() -> tuple:\n    """Korte, warme mail voor een dag zonder signalen -- houdt het dagelijkse contactmoment in stand."""\n    text_body = (\n        "Good morning from Hesty\'s\\n\\n"\n        "No bullish flips showed up on today\'s scan -- a quiet day on that front.\\n\\n"\n        "Check Discover for sector rotation and top movers, or Analyse for your own portfolio.\\n\\n"\n        "-- Hesty\'s, your personal investment assistant\\n\\n"\n        "This is a screener, not investment advice."\n    )\n    html_body = """\n    <div style="font-family: -apple-system, \'Segoe UI\', Roboto, Arial, sans-serif; max-width: 600px; margin: 0 auto; background:#ffffff;">\n        <div style="background:#101825; padding: 28px 24px; border-radius: 12px 12px 0 0;">\n            <div style="color:#1FAE96; font-size:13px; font-weight:600; letter-spacing:1px; text-transform:uppercase;">Hesty\'s Daily</div>\n            <div style="color:#EAEDF1; font-size:22px; font-weight:700; margin-top:4px;">Good morning</div>\n        </div>\n        <div style="padding: 24px; border: 1px solid #E5E8EC; border-top: none; border-radius: 0 0 12px 12px;">\n            <p style="font-size:15px; color:#101825; line-height:1.5; margin-top:0;">\n                No bullish flips showed up on today\'s scan -- a quiet day on that front.\n            </p>\n            <p style="margin-top:16px; font-size:14px; color:#5B6472; line-height:1.5;">\n                Check <a href="https://hestys.streamlit.app/?view=discover" style="color:#1FAE96; font-weight:600; text-decoration:none;">Discover</a>\n                for sector rotation and top movers, or\n                <a href="https://hestys.streamlit.app/?view=analyze" style="color:#1FAE96; font-weight:600; text-decoration:none;">Analyse</a> for your own portfolio.\n            </p>\n            <p style="margin-top:24px; font-size:14px; color:#101825; font-weight:600;">&mdash; Hesty\'s, your personal investment assistant</p>\n            <p style="margin-top:16px; font-size:12px; color:#9AA1AC; font-style:italic;">This is a screener, not investment advice.</p>\n        </div>\n    </div>\n    """\n    return text_body, html_body\n\n\ndef build_email_body_daily(df_hits: pd.DataFrame) -> tuple:\n    """\n    Bouwt de dagelijkse mail -- zakelijk maar met een eigen stem: een korte,\n    op de data gebaseerde toelichting (geen hype, geen giswerk) vooraf, dan\n    de tabel, en een korte, herkenbare afsluiting namens Hesty\'s.\n    """\n    n = len(df_hits)\n    top_pick = df_hits.iloc[0]  # df_hits is al gesorteerd op score (hoog naar laag)\n\n    intro_line = (\n        f"{n} stock{\'s\' if n != 1 else \'\'} just flipped bullish on today\'s scan. "\n        f"{top_pick[\'ticker\']} leads with the highest score ({top_pick[\'score\']})."\n    )\n\n    # --- Tekst-versie ---\n    text_lines = [\n        "Good morning from Hesty\'s",\n        "",\n        intro_line,\n        "",\n        "Today\'s signals (highest score first):",\n    ]\n    for _, row in df_hits.iterrows():\n        text_lines.append(\n            f"- [{row[\'score\']}] {row[\'ticker\']}: flipped {row[\'dagen_geleden\']} day(s) ago "\n            f"after {row[\'voorgaande_trend_dagen\']} days bearish -- "\n            f"{row[\'prijs_bij_omslag\']} -> {row[\'prijs_nu\']} ({row[\'sinds_omslag_pct\']:+.2f}%)"\n        )\n    text_lines += [\n        "",\n        "See the full list, sector rotation, and top movers under Discover on the site.",\n        "",\n        "-- Hesty\'s, your personal investment assistant",\n        "",\n        "This is a screener, not investment advice.",\n    ]\n    text_body = "\\n".join(text_lines)\n\n    # --- HTML-versie: lichte achtergrond (betrouwbaarder in e-mail-clients\n    # dan een donkere), met de merk-kleur (jade) als accent ---\n    rows_html = "".join(\n        f"""<tr style="border-bottom:1px solid #E5E8EC;">\n            <td style="padding:10px 8px;font-weight:700;color:#101825;">{r[\'score\']}</td>\n            <td style="padding:10px 8px;font-weight:600;color:#101825;">{r[\'ticker\']}</td>\n            <td style="padding:10px 8px;color:#5B6472;">{r[\'flip_date\']}</td>\n            <td style="padding:10px 8px;color:#5B6472;">{r[\'dagen_geleden\']}d ago</td>\n            <td style="padding:10px 8px;color:#5B6472;">{r[\'prijs_bij_omslag\']} &rarr; {r[\'prijs_nu\']}</td>\n            <td style="padding:10px 8px;font-weight:600;color:{\'#0F8F6E\' if r[\'sinds_omslag_pct\'] >= 0 else \'#C1524A\'};">{r[\'sinds_omslag_pct\']:+.2f}%</td>\n        </tr>"""\n        for _, r in df_hits.iterrows()\n    )\n\n    html_body = f"""\n    <div style="font-family: -apple-system, \'Segoe UI\', Roboto, Arial, sans-serif; max-width: 600px; margin: 0 auto; background:#ffffff;">\n        <div style="background:#101825; padding: 28px 24px; border-radius: 12px 12px 0 0;">\n            <div style="color:#1FAE96; font-size:13px; font-weight:600; letter-spacing:1px; text-transform:uppercase;">Hesty\'s Daily</div>\n            <div style="color:#EAEDF1; font-size:22px; font-weight:700; margin-top:4px;">Good morning</div>\n        </div>\n        <div style="padding: 24px; border: 1px solid #E5E8EC; border-top: none; border-radius: 0 0 12px 12px;">\n            <p style="font-size:15px; color:#101825; line-height:1.5; margin-top:0;">{intro_line}</p>\n            <table style="width:100%; border-collapse:collapse; margin-top:16px;">\n                <tr style="border-bottom:2px solid #101825;">\n                    <th style="text-align:left; padding:8px; font-size:11px; color:#5B6472; text-transform:uppercase;">Score</th>\n                    <th style="text-align:left; padding:8px; font-size:11px; color:#5B6472; text-transform:uppercase;">Ticker</th>\n                    <th style="text-align:left; padding:8px; font-size:11px; color:#5B6472; text-transform:uppercase;">Flip Date</th>\n                    <th style="text-align:left; padding:8px; font-size:11px; color:#5B6472; text-transform:uppercase;">Since</th>\n                    <th style="text-align:left; padding:8px; font-size:11px; color:#5B6472; text-transform:uppercase;">Price</th>\n                    <th style="text-align:left; padding:8px; font-size:11px; color:#5B6472; text-transform:uppercase;">Change</th>\n                </tr>\n                {rows_html}\n            </table>\n            <p style="margin-top:20px; font-size:14px; color:#5B6472; line-height:1.5;">\n                Want sector rotation, top movers, and earnings surprises too? Check\n                <a href="https://hestys.streamlit.app/?view=discover" style="color:#1FAE96; font-weight:600; text-decoration:none;">Discover</a> on the site.\n            </p>\n            <p style="margin-top:24px; font-size:14px; color:#101825; font-weight:600;">&mdash; Hesty\'s, your personal investment assistant</p>\n            <p style="margin-top:16px; font-size:12px; color:#9AA1AC; font-style:italic;">This is a screener, not investment advice.</p>\n        </div>\n    </div>\n    """\n    return text_body, html_body\n\n\ndef main(send_own_email: bool = True) -> None:\n    tickers = build_ticker_list()\n\n    print("Fetching benchmark returns (for relative strength)...")\n    benchmark_returns = fetch_benchmark_returns_daily()\n\n    print(f"\\nScreening {len(tickers)} tickers for recent bullish Supertrend flips "\n          f"(daily, ATR length {ATR_LENGTH}, multiplier {ATR_MULTIPLIER})...\\n")\n\n    hits = []\n    movers = []\n    for ticker in tickers:\n        try:\n            df = fetch_daily(ticker)\n        except Exception as exc:\n            print(f"  {ticker}: fout bij ophalen ({exc})")\n            continue\n\n        # Dag-op-dag-verandering, voor \'top movers\' -- hergebruikt dezelfde\n        # opgehaalde data als de signaal-check hieronder, dus GEEN extra\n        # API-aanroepen nodig.\n        if not df.empty and len(df) >= 2:\n            try:\n                day_change = (df["close"].iloc[-1] / df["close"].iloc[-2] - 1) * 100\n                movers.append({"ticker": ticker, "change_pct": round(day_change, 2)})\n            except Exception:\n                pass\n\n        result = check_ticker_daily(ticker, benchmark_returns, df=df)\n        if result:\n            hits.append(result)\n            print(f"  {ticker}: SIGNAL ({result[\'dagen_geleden\']} day(s) ago, score {result[\'score\']})")\n        else:\n            print(f"  {ticker}: no recent signal")\n\n    if movers:\n        df_movers = pd.DataFrame(movers).sort_values("change_pct", ascending=False)\n        df_movers.to_csv("top_movers.csv", index=False)\n        print(f"\\nSaved {len(df_movers)} tickers\' daily change to \'top_movers.csv\'.")\n\n    if not hits:\n        print("\\nNo signals today.")\n        if send_own_email and email_is_configured():\n            send_email(subject="Daily screener: no signals today", body_text="No signals found today.")\n        return\n\n    df_hits = pd.DataFrame(hits)\n    df_hits.sort_values("score", ascending=False, inplace=True)\n\n    print(f"\\n=== {len(hits)} SIGNALS FOUND ===\\n")\n    print(df_hits.to_string(index=False))\n\n    df_hits.to_csv("supertrend_signals_daily.csv", index=False)\n    print("\\nSaved to \'supertrend_signals_daily.csv\'.")\n\n    if send_own_email and email_is_configured():\n        text_body, html_body = build_email_body_daily(df_hits)\n        send_email(subject=f"Daily screener: {len(hits)} new signals", body_text=text_body, body_html=html_body)\n\n\nif __name__ == "__main__":\n    main()\n'

WEEKLY_BATCH_CONTENT = '"""\nWekelijks batch-script: draait de gedeelde screener EN stuurt elke\ngeregistreerde gebruiker een persoonlijke e-mail over hun eigen portfolio.\n\nBedoeld om te draaien via GitHub Actions (dus GEEN Streamlit-context --\nleest configuratie via omgevingsvariabelen, niet via st.secrets zoals\nhet dashboard zelf doet).\n\nBenodigde omgevingsvariabelen (als GitHub Actions secrets, of lokaal in .env):\n  SUPABASE_URL, SUPABASE_ANON_KEY\n  EMAIL_SMTP_SERVER, EMAIL_SMTP_PORT, EMAIL_ADDRESS, EMAIL_APP_PASSWORD\n\nGebruik: python weekly_batch.py\n"""\nfrom __future__ import annotations\n\nimport os\n\nimport pandas as pd\nfrom dotenv import load_dotenv\nfrom supabase import create_client\n\nload_dotenv()\n\nimport screener\nfrom portfolio_watch import check_holding, build_email_body\nfrom emailer import send_email\n\n\ndef get_supabase_client():\n    url = os.environ["SUPABASE_URL"]\n    key = os.environ["SUPABASE_ANON_KEY"]\n    return create_client(url, key)\n\n\ndef get_all_users_with_holdings() -> dict:\n    """Geeft alle gebruikers en hun posities terug, gegroepeerd per e-mailadres."""\n    client = get_supabase_client()\n    response = client.table("portfolio_holdings").select("*").execute()\n\n    grouped: dict[str, list[dict]] = {}\n    for row in response.data:\n        grouped.setdefault(row["user_email"], []).append(row)\n    return grouped\n\n\ndef get_all_preferences() -> dict:\n    """Geeft de e-mail-voorkeuren van ALLE gebruikers terug die ooit iets hebben ingesteld."""\n    client = get_supabase_client()\n    response = client.table("user_preferences").select("*").execute()\n    return {row["user_email"]: row for row in response.data}\n\n\ndef run_screener_shared() -> None:\n    """\n    Draait de gedeelde screener 1x -- de resultaten (CSV\'s, incl. Snowball\n    Signal en Rocket List) zijn voor iedereen zichtbaar op de website.\n    send_own_email=False, want de vaste mail naar het eigen GitHub-\n    secrets-adres zou dubbel op kunnen tellen met de per-gebruiker-opt-in-\n    mail hieronder (run_weekly_signals_emails) als dat hetzelfde adres is.\n    """\n    print("=== Gedeelde screener draaien (publiek, voor iedereen zichtbaar) ===")\n    screener.main(send_own_email=False)\n\n\ndef _format_momentocrats_row(row) -> str:\n    return (f"[score {row[\'score\']}] {row[\'ticker\']}: flipped {row[\'weken_geleden\']} week(en) ago "\n            f"({row[\'sinds_omslag_pct\']:+.2f}% since)")\n\n\ndef _format_snowball_row(row) -> str:\n    return (f"{row[\'ticker\']}: ROIC {row[\'roic_pct\']:.1f}%, "\n            f"{row[\'afwijking_fair_value_pct\']:+.1f}% vs. fair value")\n\n\ndef _format_rocket_row(row) -> str:\n    return (f"{row[\'ticker\']}: {row[\'groei_pct\']:.1f}% growth, "\n            f"{row[\'relatieve_sterkte\']:+.1f}% relative strength")\n\n\nSIGNAL_TYPES = {\n    "momentocrats": {\n        "pref_key": "wants_momentocrats_email", "csv": "supertrend_signals.csv",\n        "title": "Momentocrats", "emoji": "📡", "sort_by": "score", "sort_asc": False,\n        "formatter": _format_momentocrats_row,\n    },\n    "snowball": {\n        "pref_key": "wants_snowball_email", "csv": "snowball_signals.csv",\n        "title": "Snowballers", "emoji": "🐦", "sort_by": "afwijking_fair_value_pct", "sort_asc": True,\n        "formatter": _format_snowball_row,\n    },\n    "rocket": {\n        "pref_key": "wants_rocket_email", "csv": "rocket_list_signals.csv",\n        "title": "Rocket List", "emoji": "🚀", "sort_by": "groei_pct", "sort_asc": False,\n        "formatter": _format_rocket_row,\n    },\n}\n\n\ndef build_weekly_signals_email(sections: list, is_premium: bool = False) -> tuple:\n    """\n    Bouwt 1 gecombineerde mail voor alle signaal-types die deze gebruiker\n    heeft aangevinkt.\n\n    Toont altijd top 3 per signaal, OOK voor premium -- een mail met\n    tientallen regels per signaal is geen prettige samenvatting meer,\n    dat is precies waar Discover (met een scrollbare tabel) voor is.\n    De \'is_premium\'-parameter blijft bestaan voor later (zodra premium\n    functioneel is), maar beïnvloedt de mail-inhoud nu bewust niet.\n\n    sections: lijst van dicts met keys \'title\', \'emoji\', \'df\', \'formatter\'.\n    """\n    display_limit = 3\n    text_lines = ["Good morning from Hesty\'s -- your weekly signals are in.", ""]\n    html_sections_list = []\n\n    for section in sections:\n        total_this_section = len(section["df"])\n        top_n = section["df"].head(display_limit)\n        text_lines.append(f"{section[\'emoji\']} {section[\'title\']} (top {len(top_n)} of {total_this_section} total):")\n        for _, row in top_n.iterrows():\n            text_lines.append(f"  - {section[\'formatter\'](row)}")\n        text_lines.append("")\n\n        rows_html = "".join(\n            f"<li style=\'padding:4px 0;color:#101825;\'>{section[\'formatter\'](row)}</li>"\n            for _, row in top_n.iterrows()\n        )\n        html_sections_list.append(f"""\n        <h4 style="color:#101825; font-size:16px; margin:20px 0 8px 0;">{section[\'emoji\']} {section[\'title\']}</h4>\n        <ul style="margin:0; padding-left:20px; font-size:14px;">{rows_html}</ul>\n        """)\n\n    text_lines += [\n        "See the full lists, sector rotation, and top movers under Discover on the site.",\n        "",\n        "-- Hesty\'s, your personal investment assistant",\n        "",\n        "This is a screener, not investment advice.",\n    ]\n    text_body = "\\n".join(text_lines)\n\n    html_body = f"""\n    <div style="font-family: -apple-system, \'Segoe UI\', Roboto, Arial, sans-serif; max-width: 600px; margin: 0 auto; background:#ffffff;">\n        <div style="background:#101825; padding: 28px 24px; border-radius: 12px 12px 0 0;">\n            <div style="color:#1FAE96; font-size:13px; font-weight:600; letter-spacing:1px; text-transform:uppercase;">Hesty\'s Weekly</div>\n            <div style="color:#EAEDF1; font-size:22px; font-weight:700; margin-top:4px;">Your weekly signals are in</div>\n        </div>\n        <div style="padding: 24px; border: 1px solid #E5E8EC; border-top: none; border-radius: 0 0 12px 12px;">\n            {\'\'.join(html_sections_list)}\n            <p style="margin-top:20px; font-size:14px; color:#5B6472; line-height:1.5;">\n                See the full lists, sector rotation, and top movers under\n                <a href="https://hestys.streamlit.app/?view=discover" style="color:#1FAE96; font-weight:600; text-decoration:none;">Discover</a> on the site.\n            </p>\n            <p style="margin-top:24px; font-size:14px; color:#101825; font-weight:600;">&mdash; Hesty\'s, your personal investment assistant</p>\n            <p style="margin-top:16px; font-size:12px; color:#9AA1AC; font-style:italic;">This is a screener, not investment advice.</p>\n        </div>\n    </div>\n    """\n    return text_body, html_body\n\n\ndef run_weekly_signals_emails(preferences: dict) -> None:\n    """\n    Stuurt 1 gecombineerde mail per gebruiker, met alleen de signaal-types\n    waar diegene zich voor heeft aangemeld (top 3 gratis / top 10 premium).\n    """\n    print("\\n=== Wekelijkse signalen-mails versturen aan opt-in-gebruikers ===")\n\n    # Laad elke CSV maar 1x, niet per gebruiker opnieuw\n    csv_cache = {}\n    for key, config in SIGNAL_TYPES.items():\n        if os.path.exists(config["csv"]):\n            df = pd.read_csv(config["csv"])\n            if not df.empty:\n                df = df.sort_values(config["sort_by"], ascending=config["sort_asc"])\n                csv_cache[key] = df\n\n    for user_email, prefs in preferences.items():\n        sections = []\n        for key, config in SIGNAL_TYPES.items():\n            if not prefs.get(config["pref_key"]):\n                continue\n            if key not in csv_cache:\n                continue\n            sections.append({\n                "title": config["title"], "emoji": config["emoji"],\n                "df": csv_cache[key], "formatter": config["formatter"],\n            })\n\n        if not sections:\n            continue\n\n        is_premium = bool(prefs.get("is_premium", False))\n        print(f"  {user_email} ({\'premium\' if is_premium else \'free\'}): {\', \'.join(s[\'title\'] for s in sections)}")\n        text_body, html_body = build_weekly_signals_email(sections, is_premium=is_premium)\n        total_signals = sum(len(s["df"]) for s in sections)\n        subject = f"Hesty\'s Weekly: {total_signals} new signal(s) this week"\n        send_email(subject=subject, body_text=text_body, body_html=html_body, to_email=user_email)\n\n\ndef run_portfolio_emails(preferences: dict) -> None:\n    """\n    Checkt en mailt elke geregistreerde gebruiker zijn eigen, persoonlijke\n    portfolio -- behalve als hij dat expliciet heeft uitgezet. Standaard AAN\n    (ook voor gebruikers die nog nooit hun voorkeuren hebben aangepast).\n    """\n    print("\\n=== Persoonlijke portfolio-e-mails versturen ===")\n    users = get_all_users_with_holdings()\n    print(f"{len(users)} gebruiker(s) gevonden met een portfolio.")\n\n    for user_email, holdings in users.items():\n        user_prefs = preferences.get(user_email, {})\n        if not user_prefs.get("wants_portfolio_email", True):\n            print(f"\\n--- {user_email}: heeft de portfolio-mail uitgezet, overgeslagen ---")\n            continue\n\n        print(f"\\n--- {user_email} ({len(holdings)} positie(s)) ---")\n        results = []\n        for holding in holdings:\n            result = check_holding(holding["naam"], holding["ticker"])\n            if result:\n                results.append(result)\n\n        if not results:\n            print("  Geen van de posities kon gecheckt worden -- geen mail verstuurd.")\n            continue\n\n        df = pd.DataFrame(results)\n        text_body, html_body = build_email_body(df)\n        n_changed = int(df["recent_gewijzigd"].sum())\n        subject = (\n            f"Portfolio Watch: {n_changed} wijziging(en)"\n            if n_changed > 0 else "Portfolio Watch: geen wijzigingen"\n        )\n\n        send_email(subject=subject, body_text=text_body, body_html=html_body, to_email=user_email)\n\n\nif __name__ == "__main__":\n    run_screener_shared()\n    all_preferences = get_all_preferences()\n    run_weekly_signals_emails(all_preferences)\n    run_portfolio_emails(all_preferences)\n    print("\\nKlaar.")\n'

with open("portfolio_watch.py", "w", encoding="utf-8") as f:
    f.write(PORTFOLIO_WATCH_CONTENT)
